1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: Damage[] };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_RATE = 0.1;
12	
13	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
23	  sword: 1000,
24	  amulet: 600,
25	  staff: 800,
26	  potion: 400,
27	  rune: 250,
28	  moonstone: 250,
29	};
30	
31	const insuranceValueForType = (type: string): number => INSURANCE_VALUE_BY_TYPE[type] ?? 0;
32	
33	const DEDUCTIBLE = 100;
34	const CAP_MULTIPLIER = 2;
35	
36	const policyInsuranceSum = (items: Item[]): number =>
37	  sum(items.map((item) => insuranceValueForType(item.type)));
38	
39	const processClaim = (
40	  items: Item[],
41	  incident: Incident,
42	  remainingCap: number,
43	): { payout: number; remainingCap: number } => {
44	  const rawPayout = sum(
45	    incident.damages.map((damage) => Math.max(0, damage.amount - DEDUCTIBLE)),
46	  );
47	  const payout = Math.min(rawPayout, remainingCap);
48	  return { payout, remainingCap: remainingCap - payout };
49	};
50	
51	const basePremiumForType = (type: string): number => BASE_PREMIUM_BY_TYPE[type] ?? 0;
52	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
53	
54	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
55	const BLOCK_SIZE = 3;
56	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
57	
58	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
59	
60	const componentGroupPremium = (type: string, count: number): number =>
61	  count === BLOCK_SIZE ? BLOCK_OF_THREE_BASE_PREMIUM : count * basePremiumForType(type);
62	
63	const groupByType = (items: Item[]): Map<string, number> => {
64	  const counts = new Map<string, number>();
65	  for (const item of items) {
66	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
67	  }
68	  return counts;
69	};
70	
71	const sum = (values: number[]): number => values.reduce((total, value) => total + value, 0);
72	
73	const policyBasePremium = (items: Item[]): number => {
74	  const mainItems = items.filter((item) => !isComponent(item));
75	  const componentItems = items.filter(isComponent);
76	  const componentCounts = groupByType(componentItems);
77	
78	  const mainTotal = sum(mainItems.map(itemBasePremium));
79	  const componentTotal = sum(
80	    [...componentCounts].map(([type, count]) => componentGroupPremium(type, count)),
81	  );
82	
83	  return mainTotal + componentTotal;
84	};
85	
86	const CURSE_SURCHARGE_RATE = 0.5;
87	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
88	const HIGH_ENCHANTMENT_THRESHOLD = 5;
89	
90	const itemSurcharges = (item: Item): number => {
91	  const base = itemBasePremium(item);
92	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
93	  const highEnch =
94	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
95	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
96	      : 0;
97	  return curse + highEnch;
98	};
99	
100	const LOYALTY_DISCOUNT_RATE = 0.2;
101	const LOYALTY_YEARS_THRESHOLD = 2;
102	const FOLLOWUP_DISCOUNT_RATE = 0.15;
103	
104	const perItemSurcharges = (items: Item[]): number => sum(items.map(itemSurcharges));
105	
106	const policyWideDiscounts = (
107	  basePremium: number,
108	  customer: Customer,
109	  isFollowUp: boolean,
110	): number => {
111	  const loyalty =
112	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
113	  const followUp = isFollowUp ? basePremium * FOLLOWUP_DISCOUNT_RATE : 0;
114	  return loyalty + followUp;
115	};
116	
117	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
118	  const basePremium = policyBasePremium(items);
119	  const surcharges = perItemSurcharges(items);
120	  const discounts = policyWideDiscounts(basePremium, customer, isFollowUp);
121	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
122	  const premiumBeforeFee = Math.ceil(basePremium + surcharges - discounts + firstInsurance);
123	  return premiumBeforeFee + PROCESSING_FEE;
124	};
125	
126	export const runScenario = (scenario: Scenario): unknown => {
127	  let quoteCount = 0;
128	  const policies: Item[][] = [];
129	  const remainingCaps: number[] = [];
130	  const results = scenario.steps.map((step) => {
131	    if (step.op === "quote") {
132	      const isFollowUp = quoteCount > 0;
133	      quoteCount += 1;
134	      policies.push(step.items);
135	      remainingCaps.push(policyInsuranceSum(step.items) * CAP_MULTIPLIER);
136	      return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
137	    }
138	    const policyItems = policies[step.policy];
139	    const result = processClaim(policyItems, step.incident, remainingCaps[step.policy]);
140	    remainingCaps[step.policy] = result.remainingCap;
141	    return result;
142	  });
143	  return { results };
144	};
